section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/aws-cli-compute.json",
  "type": "object",
  "required": [
    "artefact_id",
    "operation_type",
    "profile_explicit",
    "region_explicit",
    "output_format",
    "uses_waiters_not_sleep",
    "embedded_credentials_present",
    "owner"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "stable script id"
    },
    "operation_type": {
      "type": "string",
      "description": "enum: ec2 | s3 | lambda"
    },
    "profile_explicit": {
      "type": "boolean",
      "description": "true (--profile or AWS_PROFILE assertion present)"
    },
    "region_explicit": {
      "type": "boolean",
      "description": "true"
    },
    "output_format": {
      "type": "string",
      "description": "enum: json"
    },
    "uses_waiters_not_sleep": {
      "type": "boolean",
      "description": "true"
    },
    "embedded_credentials_present": {
      "type": "boolean",
      "description": "must be false"
    },
    "owner": {
      "type": "string",
      "description": "single named handle"
    }
  }
}
